import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Routes } from '@angular/router';



const routes: Routes = [{
  path: 'bai',
  loadChildren: () => import('./bai/bai.module').then(m => m.BAIModule)
}, {
  path: 'bpr',
  loadChildren: () => import('./bpr/bpr.module').then(m => m.BPRModule)
}, {
  path: 'cui',
  loadChildren: () => import('./cui/cui.module').then(m => m.CUIModule)
}, {
  path: 'geo',
  loadChildren: () => import('./geo/geo.module').then(m => m.GEOModule)
}, {
  path: 'ios',
  loadChildren: () => import('./ios/ios.module').then(m => m.IOSModule)
}, {
  path: 'pct',
  loadChildren: () => import('./pct/pct.module').then(m => m.PCTModule)
}];

@NgModule({
  declarations: [],
  imports: [
    CommonModule,
    RouterModule.forChild(routes),
  ],
  exports: [RouterModule]
})
export class FDPRoutingModule { }
